import { Intent, MethodIntent, z } from 'mpay'

const tempoCharge = MethodIntent.fromIntent(Intent.charge, {
  method: 'tempo',
  schema: {
    credential: {
      payload: z.object({
        signature: z.string(),
        type: z.literal('transaction'),
      }),
    },
    request: {
      methodDetails: z.object({
        chainId: z.number(),
      }),
      requires: ['recipient'],
    },
  },
})

